export class ThemeEvents{static dialogOpening="dialog:opening";static dialogOpen="dialog:open";static dialogClosing="dialog:closing";static dialogClose="dialog:close";static CountdownStart="countdown:start";static CountdownEnd="countdown:end";static variantSelected="variant:selected";static variantUpdate="variant:update";static cartUpdate="cart:update";static cartReload="cart:reload";static cartCount="cart:count:update";static cartError="cart:error";static discountUpdate="discount:update";static currencyUpdate="currency:update";static cartDrawerRender="cart:drawer:render";static cartMainRender="cart:main:render";static filterUpdate="filter:update";static mediaStartedPlaying="media:started-playing";static zoomMediaSelected="zoom-media:selected";static quantitySelectorUpdate="quantity-selector:update";static megaMenuHover="megaMenu:hover";static progressBarChange="progress-bar:change"}export class CartCountEvent extends Event{constructor(t,e){super(ThemeEvents.cartCount,{bubbles:!1}),this.detail={item_count:t,total_price:e}}}export class CartUpdateEvent extends Event{constructor(t,e,a,r,s,c){super(ThemeEvents.cartUpdate,{bubbles:!0}),this.detail={resource:t,sourceId:e,cartData:a,actionAfterATC:r,source:s,data:{...c}}}}export class CartAddEvent extends Event{constructor(t,e,a,r,s,c){super(CartAddEvent.eventName,{bubbles:!0}),this.detail={resource:t,sourceId:e,cartData:a,actionAfterATC:r,source:s,data:{...c}}}static eventName=ThemeEvents.cartUpdate}export class QuantitySelectorUpdateEvent extends Event{constructor(t,e){super(ThemeEvents.quantitySelectorUpdate,{bubbles:!0}),this.detail={quantity:t,line:e}}}export class CartErrorEvent extends Event{constructor(t,e){super(ThemeEvents.cartError,{bubbles:!0}),this.detail={sourceId:t,data:{message:e}}}}